    app.list_calls = Value("i", 0)
    app.style_calls = Value("i", 0)
    app.preceding_calls = Value("i", 0)
    app.total_calls = Value("i", 0)

    @app.callback(
        Output("list-container", "children"),
        Output("new-item", "value"),
        Input("add", "n_clicks"),
        Input("new-item", "n_submit"),
        Input("clear-done", "n_clicks"),
        State("new-item", "value"),
        State({"item": ALL}, "children"),
        State({"item": ALL, "action": "done"}, "value"),
    )
    def edit_list(add, add2, clear, new_item, items, items_done):
        app.list_calls.value += 1
        triggered = [t["prop_id"] for t in dash.callback_context.triggered]
        adding = len(
            [1 for i in triggered if i in ("add.n_clicks", "new-item.n_submit")]
        )
        clearing = len([1 for i in triggered if i == "clear-done.n_clicks"])
        new_spec = [
            (text, done)
            for text, done in zip(items, items_done)
            if not (clearing and done)
        ]
        if adding:
            new_spec.append((new_item, []))

        # Check callback context use of grouping
        assert not dash.callback_context.using_args_grouping
        assert not dash.callback_context.using_outputs_grouping

        new_list = [
            html.Div(
                [
                    dcc.Checklist(
                        id={"item": i, "action": "done"},
                        options=[{"label": "", "value": "done"}],
                        value=done,
                        style={"display": "inline"},
                    ),
                    html.Div(
                        text, id={"item": i}, style=style_done if done else style_todo
                    ),
                    html.Div(id={"item": i, "preceding": True}, style=style_todo),
                ],
                style={"clear": "both"},
            )
            for i, (text, done) in enumerate(new_spec)
        ]
        return [new_list, "" if adding else new_item]

    @app.callback(
        Output({"item": MATCH}, "style"),
        Input({"item": MATCH, "action": "done"}, "value"),
    )
    def mark_done(done):
        app.style_calls.value += 1
        return style_done if done else style_todo

    @app.callback(
        Output({"item": MATCH, "preceding": True}, "children"),
        Input({"item": ALLSMALLER, "action": "done"}, "value"),
        Input({"item": MATCH, "action": "done"}, "value"),
    )
    def show_preceding(done_before, this_done):
        app.preceding_calls.value += 1
        if this_done:
            return ""
        all_before = len(done_before)
        done_before = len([1 for d in done_before if d])
        out = "{} of {} preceding items are done".format(done_before, all_before)
        if all_before == done_before:
            out += " DO THIS NEXT!"
        return out

    @app.callback(
        Output("totals", "children"), Input({"item": ALL, "action": "done"}, "value")
    )
    def show_totals(done):
        app.total_calls.value += 1
        count_all = len(done)
        count_done = len([d for d in done if d])
        result = "{} of {} items completed".format(count_done, count_all)
        if count_all:
            result += " - {}%".format(int(100 * count_done / count_all))
        return result

    return app

def test_grbs006_graph_update_frames(dash_dcc):
    app = Dash(__name__)

    def get_scatter(multiplier, offset):
        return go.Scatter(
            x=list(map(lambda n: n * multiplier, [0, 1, 2])),
            y=list(map(lambda n: n + offset, [0, 1, 2])),
            mode="markers",
        )

    def get_figure(data, frames, title):
        return go.Figure(
            data=data,
            layout=go.Layout(
                title=title,
                yaxis=dict(range=[-1, 5]),
                xaxis=dict(range=[-3, 3]),
                updatemenus=[
                    dict(
                        type="buttons",
                        buttons=[
                            dict(
                                label="Play",
                                method="animate",
                                args=[
                                    None,
                                    {
                                        "frame": {"duration": 100, "redraw": True},
                                        "fromcurrent": False,
                                        "transition": {
                                            "duration": 500,
                                            "easing": "quadratic-in-out",
                                        },
                                    },
                                ],
                            )
                        ],
                    )
                ],
            ),
            frames=frames,
        )

    app.layout = html.Div(
        [
            html.Label("Choose dataset"),
            dcc.RadioItems(
                id="change-data",
                options=[
                    {"label": "No data", "value": 0},
                    {"label": "Data A", "value": 1},
                    {"label": "Data B", "value": 2},
                ],
                value=0,
            ),
            dcc.Graph(
                id="test-change",
                animate=True,
                animation_options={"frame": {"redraw": True}},
            ),
            html.Div(id="relayout-data"),
        ]
    )

    @app.callback(
        Output("relayout-data", "children"),
        [Input("test-change", "figure")],
    )
    def show_relayout_data(data):
        frames = data.get("frames", [])
        if frames:
            return json.dumps(frames[0]["data"][0]["x"])
        return ""

    @app.callback(
        Output("test-change", "figure"),
        Input("change-data", "value"),
    )
    def set_data(dataset):
        if dataset == 1:
            title = "Dataset A"
            data = get_scatter(1, 0)
            frames = [
                go.Frame(data=get_scatter(1, 1)),
            ]
        elif dataset == 2:
            title = "Dataset B"
            data = get_scatter(-1, 0)
            frames = [
                go.Frame(data=get_scatter(-1, 1)),
            ]
        else:
            title = "Select a dataset"
            data = []
            frames = []

        fig = get_figure(data, frames, title)
        return fig

    dash_dcc.start_server(app)
    dash_dcc.wait_for_element("#test-change")

    dash_dcc.find_elements('input[type="radio"]')[0].click()
    assert dash_dcc.wait_for_text_to_equal(
        "#relayout-data", ""
    ), "initial graph data must contain empty string"

    dash_dcc.find_elements('input[type="radio"]')[1].click()
    assert dash_dcc.wait_for_text_to_equal(
        "#relayout-data", "[0, 1, 2]"
    ), "graph data must contain frame [0,1,2]"

    dash_dcc.find_elements('input[type="radio"]')[2].click()
    assert dash_dcc.wait_for_text_to_equal(
        "#relayout-data", "[0, -1, -2]"
    ), "graph data must contain frame [0,-1,-2]"

def test_rdrh001_request_hooks(dash_duo):
    app = Dash(__name__)

    app.index_string = """<!DOCTYPE html>
    <html>
        <head>
            {%metas%}
            <title>{%title%}</title>
            {%favicon%}
            {%css%}
        </head>
        <body>
            <div id="top">Testing custom DashRenderer</div>
            {%app_entry%}
            <footer>
                {%config%}
                {%scripts%}
                <script id="_dash-renderer" type"application/json">
                    const renderer = new DashRenderer({
                        request_pre: (payload) => {
                            var output = document.getElementById('output-pre')
                            var outputPayload = document.getElementById('output-pre-payload')
                            if(output) {
                                output.innerHTML = 'request_pre changed this text!';
                            }
                            if(outputPayload) {
                                outputPayload.innerHTML = JSON.stringify(payload);
                            }
                        },
                        request_post: (payload, response) => {
                            var output = document.getElementById('output-post')
                            var outputPayload = document.getElementById('output-post-payload')
                            var outputResponse = document.getElementById('output-post-response')
                            if(output) {
                                output.innerHTML = 'request_post changed this text!';
                            }
                            if(outputPayload) {
                                outputPayload.innerHTML = JSON.stringify(payload);
                            }
                            if(outputResponse) {
                                outputResponse.innerHTML = JSON.stringify(response);
                            }
                        }
                    })
                </script>
            </footer>
            <div id="bottom">With request hooks</div>
        </body>
    </html>"""

    app.layout = html.Div(
        [
            dcc.Input(id="input", value="initial value"),
            html.Div(
                html.Div(
                    [
                        html.Div(id="output-1"),
                        html.Div(id="output-pre"),
                        html.Div(id="output-pre-payload"),
                        html.Div(id="output-post"),
                        html.Div(id="output-post-payload"),
                        html.Div(id="output-post-response"),
                    ]
                )
            ),
        ]
    )

    @app.callback(Output("output-1", "children"), [Input("input", "value")])
    def update_output(value):
        return value

    dash_duo.start_server(app)

    _in = dash_duo.find_element("#input")
    dash_duo.clear_input(_in)

    _in.send_keys("fire request hooks")

    dash_duo.wait_for_text_to_equal("#output-1", "fire request hooks")
    dash_duo.wait_for_text_to_equal("#output-pre", "request_pre changed this text!")
    dash_duo.wait_for_text_to_equal("#output-post", "request_post changed this text!")

    assert json.loads(dash_duo.find_element("#output-pre-payload").text) == {
        "output": "output-1.children",
        "outputs": {"id": "output-1", "property": "children"},
        "changedPropIds": ["input.value"],
        "parsedChangedPropsIds": ["input.value"],
        "inputs": [{"id": "input", "property": "value", "value": "fire request hooks"}],
    }

    assert json.loads(dash_duo.find_element("#output-post-payload").text) == {
        "output": "output-1.children",
        "outputs": {"id": "output-1", "property": "children"},
        "changedPropIds": ["input.value"],
        "parsedChangedPropsIds": ["input.value"],
        "inputs": [{"id": "input", "property": "value", "value": "fire request hooks"}],
    }

    assert json.loads(dash_duo.find_element("#output-post-response").text) == {
        "output-1": {"children": "fire request hooks"}
    }

    assert dash_duo.find_element("#top").text == "Testing custom DashRenderer"
    assert dash_duo.find_element("#bottom").text == "With request hooks"

    assert dash_duo.get_logs() == []

def test_tagr001_graph_does_not_resize_in_tabs(dash_dcc, is_eager):
    app = Dash(__name__, eager_loading=is_eager)
    app.layout = html.Div(
        [
            html.H1("Dash Tabs component demo"),
            dcc.Tabs(
                id="tabs-example",
                value="tab-1-example",
                children=[
                    dcc.Tab(label="Tab One", value="tab-1-example", id="tab-1"),
                    dcc.Tab(label="Tab Two", value="tab-2-example", id="tab-2"),
                    dcc.Tab(
                        label="Tab Three",
                        value="tab-3-example",
                        id="tab-3",
                        disabled=True,
                        disabled_className="disabled-tab",
                    ),
                ],
            ),
            html.Div(id="tabs-content-example"),
        ]
    )

    @app.callback(
        Output("tabs-content-example", "children"),
        [Input("tabs-example", "value")],
    )
    def render_content(tab):
        if tab == "tab-1-example":
            return html.Div(
                [
                    html.H3("Tab content 1"),
                    dcc.Graph(
                        id="graph-1-tabs",
                        figure={
                            "data": [{"x": [1, 2, 3], "y": [3, 1, 2], "type": "bar"}]
                        },
                    ),
                ]
            )
        elif tab == "tab-2-example":
            return html.Div(
                [
                    html.H3("Tab content 2"),
                    dcc.Graph(
                        id="graph-2-tabs",
                        figure={
                            "data": [{"x": [1, 2, 3], "y": [5, 10, 6], "type": "bar"}]
                        },
                    ),
                ]
            )

    dash_dcc.driver.set_window_size(800, 600)
    dash_dcc.start_server(app)

    tab_one = dash_dcc.wait_for_element("#tab-1")
    tab_two = dash_dcc.wait_for_element("#tab-2")

    # wait for disabled tab with custom className
    dash_dcc.wait_for_element("#tab-3.disabled-tab")

    WebDriverWait(dash_dcc.driver, 10).until(
        EC.element_to_be_clickable((By.ID, "tab-2"))
    )

    # wait for Graph to be ready
    WebDriverWait(dash_dcc.driver, 10).until(
        EC.visibility_of_element_located((By.CSS_SELECTOR, "#graph-1-tabs .main-svg"))
    )

    is_eager = "eager" if is_eager else "lazy"

    dash_dcc.percy_snapshot(
        f"Tabs with Graph - initial (graph should not resize) ({is_eager})"
    )
    tab_two.click()

    # wait for Graph to be ready
    WebDriverWait(dash_dcc.driver, 10).until(
        EC.visibility_of_element_located((By.CSS_SELECTOR, "#graph-2-tabs .main-svg"))
    )

    dash_dcc.percy_snapshot(
        f"Tabs with Graph - clicked tab 2 (graph should not resize) ({is_eager})"
    )

    WebDriverWait(dash_dcc.driver, 10).until(
        EC.element_to_be_clickable((By.ID, "tab-1"))
    )

    tab_one.click()

    # wait for Graph to be loaded after clicking
    WebDriverWait(dash_dcc.driver, 10).until(
        EC.visibility_of_element_located((By.CSS_SELECTOR, "#graph-1-tabs .main-svg"))
    )

    dash_dcc.percy_snapshot(
        f"Tabs with Graph - clicked tab 1 (graph should not resize) ({is_eager})"
    )

    assert dash_dcc.get_logs() == []

def test_hook012_get_app_available_in_hooks_on_routes(hook_cleanup, dash_duo):
    """Test that get_app() is available during hooks when @with_app_context decorated routes are called."""

    # Track which hooks were able to access get_app()
    hook_access_results = {
        "layout_hook": False,
        "error_hook": False,
        "callback_hook": False,
    }

    @hooks.layout()
    def layout_hook(layout):
        try:
            retrieved_app = get_app()
            hook_access_results["layout_hook"] = retrieved_app is not None
        except Exception:
            hook_access_results["layout_hook"] = False
        return layout

    @hooks.error()
    def error_hook(error):
        try:
            retrieved_app = get_app()
            hook_access_results["error_hook"] = retrieved_app is not None
        except Exception:
            hook_access_results["error_hook"] = False

    @hooks.callback(
        Output("hook-output", "children"),
        Input("hook-button", "n_clicks"),
        prevent_initial_call=True,
    )
    def callback_hook(n_clicks):
        try:
            retrieved_app = get_app()
            hook_access_results["callback_hook"] = retrieved_app is not None
            return f"Hook callback: {n_clicks}"
        except Exception as err:
            hook_access_results["callback_hook"] = False
            return f"Error in hook callback: {err}"

    app = Dash(__name__)
    app.layout = [
        html.Div("Test get_app in hooks", id="main"),
        html.Button("Click for callback", id="button"),
        html.Div(id="output"),
        html.Button("Hook callback", id="hook-button"),
        html.Div(id="hook-output"),
        html.Button("Error", id="error-btn"),
        html.Div(id="error-output"),
    ]

    @app.callback(
        Output("output", "children"),
        Input("button", "n_clicks"),
        prevent_initial_call=True,
    )
    def test_callback(n_clicks):
        return f"Clicked {n_clicks} times"

    @app.callback(
        Output("error-output", "children"),
        Input("error-btn", "n_clicks"),
        prevent_initial_call=True,
    )
    def error_callback(n_clicks):
        if n_clicks:
            raise ValueError("Test error for hook")
        return ""

    dash_duo.start_server(app)

    # Test the @with_app_context decorated routes

    # 2. Test layout hook via index route (GET /)
    dash_duo.wait_for_text_to_equal("#main", "Test get_app in hooks")

    # 3. Test callback hook via dispatch route (POST /_dash-update-component)
    dash_duo.wait_for_element("#hook-button").click()
    dash_duo.wait_for_text_to_equal("#hook-output", "Hook callback: 1")

    # 4. Test error hook via dispatch route when error occurs
    dash_duo.wait_for_element("#error-btn").click()
    # Give error hook time to execute
    import time

    time.sleep(0.5)

    # Verify that get_app() worked in hooks during route calls with @with_app_context
    assert hook_access_results[
        "layout_hook"
    ], "get_app() should be accessible in layout hook when serve_layout/index routes have @with_app_context"
    assert hook_access_results[
        "callback_hook"
    ], "get_app() should be accessible in callback hook when dispatch route has @with_app_context"
    assert hook_access_results[
        "error_hook"
    ], "get_app() should be accessible in error hook when dispatch route has @with_app_context"
